class Solution:
    def wordPattern(self, pattern: str, s: str) -> bool:
        words = s.split()
        if len(words) != len(pattern):
            return False
        p2w, w2p = {}, {}
        for ch, w in zip(pattern, words):
            if p2w.get(ch, w) != w or w2p.get(w, ch) != ch:
                return False
            p2w[ch] = w
            w2p[w] = ch
        return True

